import { NavLink } from "react-router-dom";

function Sidebar() {
  return (
    <aside className="sidebar">
      <h1 className="logo">Eventra</h1>

      <nav className="sidebar-nav">
        <NavLink to="/" end>🏠 Головна</NavLink>
        <NavLink to="/events">📅 Події</NavLink>
        <NavLink to="/tutors">🎓 Репетитори</NavLink>
        <NavLink to="/profile">👤 Профіль</NavLink>
        <NavLink to="/create-event">➕ Створити подію</NavLink>
      </nav>

      <div className="sidebar-card">
        <div className="card-icon">👥</div>
        <h3>Знайди людей і події за інтересами!</h3>
        <p>Приєднуйся до спільнот, відкривай нові події та знайомся з цікавими людьми.</p>
        <button>Приєднатися</button>
      </div>
    </aside>
  );
}

export default Sidebar;
